import styled from "styled-components";
import { darkTheme } from "../../../../assets/global-styles/colors";

export const StyledDiv = styled.div`
  height: 70vh;
  text-align: center;
  padding: 0 100px 0 100px;
  .boldTitle {
    text-transform: uppercase;
    font-weight: bold;
    color: yellow;
  }
  .first_letter {
    font-size: 70px;
    color: red;
    display: block;
    border: 1px solid white;
    float: left;
  }
  p {
    text-align: justify;
  }
`;
